package com.pinova.service.impl;

import com.baomidou.mybatisplus.core.toolkit.*;import com.fasterxml.jackson.databind.*;import com.pinova.common.error.*;import com.pinova.mapper.*;import com.pinova.pojo.entity.*;import com.pinova.service.*;import com.pinova.service.command.*;import com.pinova.service.model.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.Instant;import java.util.*;
@Service public class AdminProductServiceImpl implements AdminProductService{
 private static final Set<String> BLOCK_TYPES=Set.of("heading","paragraph","image","gallery");
 private final ProductSpuMapper products;private final ProductSkuMapper skus;private final ProductSpuDetailMapper details;private final ProductMediaMapper media;private final ProductCategoryMapper categories;private final AdminAuthorizationService auth;private final AdminOperationAuditService audit;private final ObjectMapper json;
 public AdminProductServiceImpl(ProductSpuMapper p,ProductSkuMapper s,ProductSpuDetailMapper d,ProductMediaMapper m,ProductCategoryMapper c,AdminAuthorizationService a,AdminOperationAuditService u,ObjectMapper j){products=p;skus=s;details=d;media=m;categories=c;auth=a;audit=u;json=j;}
 @Override @Transactional(readOnly=true) public List<AdminProductResult> list(AuthenticatedAdminResult a){auth.requireSuperAdmin(a);return products.selectList(Wrappers.lambdaQuery(ProductSpu.class).orderByDesc(ProductSpu::getCreatedAt).last("LIMIT 200")).stream().map(this::aggregate).toList();}
 @Override @Transactional(readOnly=true) public AdminProductResult get(AuthenticatedAdminResult a,Long id){auth.requireSuperAdmin(a);return aggregate(requireProduct(id,false));}
 @Override @Transactional public AdminProductResult saveProduct(SaveAdminProductCommand c){auth.requireSuperAdmin(c==null?null:c.admin());validateProduct(c);ProductCategory cat=categories.selectById(c.categoryId());if(cat==null||categories.selectCount(Wrappers.lambdaQuery(ProductCategory.class).eq(ProductCategory::getParentId,cat.getId()))>0)invalid("商品必须属于有效叶子类目");Instant now=Instant.now();if(c.id()==null){if(c.status()==2)invalid("新商品必须先保存草稿和 SKU 后再上架");ProductSpu p=new ProductSpu();p.setId(IdWorker.getId());p.setShopId(c.shopId());p.setCategoryId(c.categoryId());p.setSpuCode(c.spuCode().trim().toUpperCase(Locale.ROOT));p.setName(c.name().trim());p.setSummary(norm(c.summary()));p.setProductType((short)1);p.setMainImageKey(norm(c.mainImageKey()));p.setStatus(c.status());p.setSortOrder(c.sortOrder());p.setVersion(0);p.setDeleted(false);p.setCreatedAt(now);p.setCreatedBy(c.admin().id());p.setUpdatedAt(now);p.setUpdatedBy(c.admin().id());products.insert(p);record(c.admin().id(),"CREATE",p.getId(),null);return aggregate(p);}ProductSpu p=requireProduct(c.id(),true);if(c.status()==2)validatePublish(p.getId(),c.mainImageKey());int n=products.update(null,Wrappers.lambdaUpdate(ProductSpu.class).eq(ProductSpu::getId,p.getId()).eq(ProductSpu::getVersion,c.version()).set(ProductSpu::getCategoryId,c.categoryId()).set(ProductSpu::getName,c.name().trim()).set(ProductSpu::getSummary,norm(c.summary())).set(ProductSpu::getMainImageKey,norm(c.mainImageKey())).set(ProductSpu::getStatus,c.status()).set(ProductSpu::getSortOrder,c.sortOrder()).set(ProductSpu::getPublishedAt,c.status()==2&&p.getPublishedAt()==null?now:p.getPublishedAt()).set(ProductSpu::getOffShelfAt,c.status()==3?now:p.getOffShelfAt()).set(ProductSpu::getUpdatedAt,now).set(ProductSpu::getUpdatedBy,c.admin().id()).setSql("version = version + 1"));if(n!=1)conflict();record(c.admin().id(),"UPDATE",p.getId(),null);return aggregate(products.selectById(p.getId()));}
 @Override @Transactional public AdminProductResult saveSku(SaveAdminSkuCommand c){auth.requireSuperAdmin(c==null?null:c.admin());if(c.productId()==null||c.productId()<=0||blank(c.skuCode())||c.salePriceFen()==null||c.salePriceFen()<0||c.inventoryMode()==null||(c.inventoryMode()!=1&&c.inventoryMode()!=2)||c.status()==null||(c.status()!=0&&c.status()!=1)||c.sortOrder()==null||c.sortOrder()<0||(c.id()!=null&&(c.version()==null||c.version()<0)))invalid("SKU 参数无效");ProductSpu p=requireProduct(c.productId(),true);Instant now=Instant.now();if(c.id()==null){ProductSku s=new ProductSku();s.setId(IdWorker.getId());s.setSpuId(p.getId());s.setSkuCode(c.skuCode().trim().toUpperCase(Locale.ROOT));s.setSpecSummary(norm(c.specSummary()));s.setSalePriceFen(c.salePriceFen());s.setInventoryMode(c.inventoryMode());s.setMainImageKey(norm(c.mainImageKey()));s.setBarcode(norm(c.barcode()));s.setStatus(c.status());s.setSortOrder(c.sortOrder());s.setVersion(0);s.setDeleted(false);s.setCreatedAt(now);s.setCreatedBy(c.admin().id());s.setUpdatedAt(now);s.setUpdatedBy(c.admin().id());skus.insert(s);}else{ProductSku s=skus.selectOne(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getId,c.id()).eq(ProductSku::getSpuId,p.getId()).last("FOR UPDATE"));if(s==null)invalid("SKU 不存在");int n=skus.update(null,Wrappers.lambdaUpdate(ProductSku.class).eq(ProductSku::getId,s.getId()).eq(ProductSku::getVersion,c.version()).set(ProductSku::getSpecSummary,norm(c.specSummary())).set(ProductSku::getSalePriceFen,c.salePriceFen()).set(ProductSku::getInventoryMode,c.inventoryMode()).set(ProductSku::getMainImageKey,norm(c.mainImageKey())).set(ProductSku::getBarcode,norm(c.barcode())).set(ProductSku::getStatus,c.status()).set(ProductSku::getSortOrder,c.sortOrder()).set(ProductSku::getUpdatedAt,now).set(ProductSku::getUpdatedBy,c.admin().id()).setSql("version = version + 1"));if(n!=1)conflict();}record(c.admin().id(),"SAVE_SKU",p.getId(),null);return aggregate(products.selectById(p.getId()));}
 @Override @Transactional public AdminProductResult saveDetail(SaveAdminProductDetailCommand c){auth.requireSuperAdmin(c==null?null:c.admin());ProductSpu p=requireProduct(c.productId(),true);validateDocument(c.documentJson());ProductSpuDetail d=details.selectOne(Wrappers.lambdaQuery(ProductSpuDetail.class).eq(ProductSpuDetail::getSpuId,p.getId()).last("FOR UPDATE"));Instant now=Instant.now();if(d==null){d=new ProductSpuDetail();d.setId(IdWorker.getId());d.setSpuId(p.getId());d.setContentSchemaVersion(1);d.setDetailDocument(c.documentJson());d.setPackingList(norm(c.packingList()));d.setUsageInstructions(norm(c.usageInstructions()));d.setAfterSalesNote(norm(c.afterSalesNote()));d.setVersion(0);d.setCreatedAt(now);d.setCreatedBy(c.admin().id());d.setUpdatedAt(now);d.setUpdatedBy(c.admin().id());details.insert(d);}else{if(c.version()==null||!c.version().equals(d.getVersion()))conflict();int n=details.update(null,Wrappers.lambdaUpdate(ProductSpuDetail.class).eq(ProductSpuDetail::getId,d.getId()).eq(ProductSpuDetail::getVersion,d.getVersion()).set(ProductSpuDetail::getDetailDocument,c.documentJson()).set(ProductSpuDetail::getPackingList,norm(c.packingList())).set(ProductSpuDetail::getUsageInstructions,norm(c.usageInstructions())).set(ProductSpuDetail::getAfterSalesNote,norm(c.afterSalesNote())).set(ProductSpuDetail::getUpdatedAt,now).set(ProductSpuDetail::getUpdatedBy,c.admin().id()).setSql("version = version + 1"));if(n!=1)conflict();}record(c.admin().id(),"SAVE_DETAIL",p.getId(),null);return aggregate(products.selectById(p.getId()));}
 @Override @Transactional public AdminProductResult addMedia(AddAdminProductMediaCommand c){auth.requireSuperAdmin(c==null?null:c.admin());ProductSpu p=requireProduct(c.productId(),true);if(blank(c.objectKey())||blank(c.mimeType())||!c.mimeType().startsWith("image/")||c.fileSizeBytes()==null||c.fileSizeBytes()<=0||c.fileSizeBytes()>10_000_000||c.mediaRole()==null||c.mediaRole()<1||c.mediaRole()>4||c.sortOrder()==null||c.sortOrder()<0)invalid("媒体参数无效");if(c.skuId()!=null&&skus.selectCount(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getId,c.skuId()).eq(ProductSku::getSpuId,p.getId()))==0)invalid("SKU 不属于当前商品");Instant now=Instant.now();ProductMedia m=new ProductMedia();m.setId(IdWorker.getId());m.setSpuId(c.skuId()==null?p.getId():null);m.setSkuId(c.skuId());m.setMediaType((short)1);m.setMediaRole(c.mediaRole());m.setObjectKey(c.objectKey());m.setMimeType(c.mimeType());m.setFileSizeBytes(c.fileSizeBytes());m.setWidth(c.width());m.setHeight(c.height());m.setAltText(norm(c.altText()));m.setSortOrder(c.sortOrder());m.setStatus((short)1);m.setVersion(0);m.setDeleted(false);m.setCreatedAt(now);m.setCreatedBy(c.admin().id());m.setUpdatedAt(now);m.setUpdatedBy(c.admin().id());media.insert(m);record(c.admin().id(),"ADD_MEDIA",p.getId(),null);return aggregate(products.selectById(p.getId()));}
 @Override @Transactional public void deleteProduct(AuthenticatedAdminResult a,Long productId,int version,String reason){auth.requireSuperAdmin(a);ProductSpu p=requireProduct(productId,true);requireReason(reason);if(p.getStatus()==2)invalid("上架商品必须先下架再删除");Instant now=Instant.now();int n=products.update(null,Wrappers.lambdaUpdate(ProductSpu.class).eq(ProductSpu::getId,p.getId()).eq(ProductSpu::getVersion,version).set(ProductSpu::getDeleted,true).set(ProductSpu::getDeletedAt,now).set(ProductSpu::getDeletedBy,a.id()).set(ProductSpu::getUpdatedAt,now).set(ProductSpu::getUpdatedBy,a.id()).setSql("version = version + 1"));if(n!=1)conflict();record(a.id(),"DELETE",p.getId(),reason);}
 @Override @Transactional public void deleteSku(AuthenticatedAdminResult a,Long productId,Long skuId,int version,String reason){auth.requireSuperAdmin(a);ProductSpu p=requireProduct(productId,true);requireReason(reason);if(p.getStatus()==2)invalid("上架商品的 SKU 不能删除");ProductSku s=skus.selectOne(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getId,skuId).eq(ProductSku::getSpuId,p.getId()).last("FOR UPDATE"));if(s==null)invalid("SKU 不存在");Instant now=Instant.now();int n=skus.update(null,Wrappers.lambdaUpdate(ProductSku.class).eq(ProductSku::getId,s.getId()).eq(ProductSku::getVersion,version).set(ProductSku::getDeleted,true).set(ProductSku::getDeletedAt,now).set(ProductSku::getDeletedBy,a.id()).set(ProductSku::getUpdatedAt,now).set(ProductSku::getUpdatedBy,a.id()).setSql("version = version + 1"));if(n!=1)conflict();record(a.id(),"DELETE_SKU",p.getId(),reason);}
 @Override @Transactional public void deleteMedia(AuthenticatedAdminResult a,Long productId,Long mediaId,int version,String reason){auth.requireSuperAdmin(a);ProductSpu p=requireProduct(productId,true);requireReason(reason);ProductMedia m=media.selectOne(Wrappers.lambdaQuery(ProductMedia.class).eq(ProductMedia::getId,mediaId).last("FOR UPDATE"));if(m==null)invalid("媒体不存在");if(m.getSpuId()!=null&&!m.getSpuId().equals(p.getId()))invalid("媒体不属于当前商品");if(m.getSkuId()!=null&&skus.selectCount(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getId,m.getSkuId()).eq(ProductSku::getSpuId,p.getId()))==0)invalid("媒体不属于当前商品");Instant now=Instant.now();int n=media.update(null,Wrappers.lambdaUpdate(ProductMedia.class).eq(ProductMedia::getId,m.getId()).eq(ProductMedia::getVersion,version).set(ProductMedia::getDeleted,true).set(ProductMedia::getDeletedAt,now).set(ProductMedia::getDeletedBy,a.id()).set(ProductMedia::getUpdatedAt,now).set(ProductMedia::getUpdatedBy,a.id()).setSql("version = version + 1"));if(n!=1)conflict();record(a.id(),"DELETE_MEDIA",p.getId(),reason);}
 private AdminProductResult aggregate(ProductSpu p){List<ProductSku> ss=skus.selectList(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getSpuId,p.getId()).orderByAsc(ProductSku::getSortOrder));List<Long> skuIds=ss.stream().map(ProductSku::getId).toList();var mq=Wrappers.lambdaQuery(ProductMedia.class).eq(ProductMedia::getSpuId,p.getId());if(!skuIds.isEmpty())mq.or().in(ProductMedia::getSkuId,skuIds);List<ProductMedia> mm=media.selectList(mq.orderByAsc(ProductMedia::getSortOrder));ProductSpuDetail d=details.selectOne(Wrappers.lambdaQuery(ProductSpuDetail.class).eq(ProductSpuDetail::getSpuId,p.getId()));return new AdminProductResult(p.getId(),p.getShopId(),p.getCategoryId(),p.getSpuCode(),p.getName(),p.getSummary(),p.getProductType(),p.getMainImageKey(),p.getStatus(),p.getSortOrder(),p.getVersion(),d==null?null:new AdminProductDetailResult(d.getContentSchemaVersion(),d.getDetailDocument(),d.getPackingList(),d.getUsageInstructions(),d.getAfterSalesNote(),d.getVersion()),ss.stream().map(AdminProductServiceImpl::sku).toList(),mm.stream().map(AdminProductServiceImpl::media).toList());}
 private ProductSpu requireProduct(Long id,boolean lock){if(id==null||id<=0)invalid("商品不存在");var q=Wrappers.lambdaQuery(ProductSpu.class).eq(ProductSpu::getId,id);if(lock)q.last("FOR UPDATE");ProductSpu p=products.selectOne(q);if(p==null)invalid("商品不存在");return p;}
 private void validatePublish(Long id,String image){if(blank(image)||skus.selectCount(Wrappers.lambdaQuery(ProductSku.class).eq(ProductSku::getSpuId,id).eq(ProductSku::getStatus,(short)1))==0)invalid("上架需要主图和至少一个启用 SKU");}
 private void validateDocument(String raw){try{JsonNode root=json.readTree(raw);JsonNode blocks=root==null?null:root.get("blocks");if(blocks==null||!blocks.isArray()||blocks.size()>100)invalid("详情必须包含不超过 100 个区块");for(JsonNode b:blocks)if(!b.hasNonNull("type")||!BLOCK_TYPES.contains(b.get("type").asText()))invalid("详情包含不支持的区块类型");}catch(Exception e){invalid("详情 JSON 无效");}}
 private static void validateProduct(SaveAdminProductCommand c){if(c==null||c.shopId()==null||c.shopId()<=0||c.categoryId()==null||c.categoryId()<=0||blank(c.spuCode())||blank(c.name())||c.name().trim().length()>200||c.status()==null||c.status()<0||c.status()>5||c.sortOrder()==null||c.sortOrder()<0||(c.id()!=null&&(c.version()==null||c.version()<0)))invalid("商品参数无效");}private static void requireReason(String reason){if(blank(reason)||reason.trim().length()>500)invalid("必须填写不超过 500 字的操作原因");}
 private void record(Long op,String action,Long id,String reason){audit.record(new RecordAdminAuditCommand(op,"PRODUCT",action,"PRODUCT_SPU",String.valueOf(id),null,norm(reason),null,null));}private static AdminSkuResult sku(ProductSku s){return new AdminSkuResult(s.getId(),s.getSkuCode(),s.getSpecSummary(),s.getSalePriceFen(),s.getInventoryMode(),s.getMainImageKey(),s.getBarcode(),s.getStatus(),s.getSortOrder(),s.getVersion());}private static AdminMediaResult media(ProductMedia m){return new AdminMediaResult(m.getId(),m.getSpuId(),m.getSkuId(),m.getMediaType(),m.getMediaRole(),m.getObjectKey(),m.getMimeType(),m.getFileSizeBytes(),m.getWidth(),m.getHeight(),m.getAltText(),m.getSortOrder(),m.getStatus(),m.getVersion());}private static boolean blank(String v){return v==null||v.isBlank();}private static String norm(String v){return blank(v)?null:v.trim();}private static void invalid(String m){throw new BusinessException(CommonErrorCode.INVALID_REQUEST,m);}private static void conflict(){throw new BusinessException(CommonErrorCode.INVALID_REQUEST,"商品已变化，请刷新后重试");}
}
